func TestRing_FNV_Distribution(t *testing.T) {
	r := NewRing(200)
	r.Add("n1")
	r.Add("n2")
	r.Add("n3")
	keys := make([]string, 10000)
	for i := range keys {
		keys[i] = fmt.Sprintf("dist-key-%d", i)
	}
	dist := r.Distribution(keys)
	for node, count := range dist {
		share := float64(count) / float64(len(keys))
		if share < 0.15 || share > 0.55 {
			t.Fatalf("node %s has %.2f share — FNV distribution too skewed", node, share)
		}
	}
}

func TestRing_BinaryInsertOrder(t *testing.T) {
	r := NewRing(50)
	for i := 0; i < 20; i++ {
		r.Add(fmt.Sprintf("node-%d", i))
	}
	r.mu.RLock()
	for i := 1; i < len(r.ring); i++ {
		if r.ring[i] < r.ring[i-1] {
			r.mu.RUnlock()
			t.Fatalf("ring not sorted at index %d: %d < %d", i, r.ring[i], r.ring[i-1])
		}
	}
	r.mu.RUnlock()
}

