func TestRing_LookupN_ExactMatch_StartsAtPosition(t *testing.T) {
    r := NewRing(64)
    r.Add("a")
    r.Add("b")
    r.Add("c")

    r.mu.RLock()
    midIdx := len(r.ring) / 2
    h := r.ring[midIdx]
    startNode := r.nodeMap[h]
    rep := r.replicas
    r.mu.RUnlock()

    // Key that hashes exactly to that position.
    vi := -1
    for i := 0; i < rep; i++ {
        if virtualNodeHash(startNode, i) == h {
            vi = i
            break
        }
    }
    if vi < 0 { t.Fatal("cannot locate virtual index") }
    key := startNode + "#" + itoa(vi)

    // Expected distinct nodes by walking ring from midIdx
    expected := make([]string, 0, 3)
    seen := make(map[string]bool)
    r.mu.RLock()
    for i := 0; i < len(r.ring) && len(expected) < 3; i++ {
        pos := (midIdx + i) % len(r.ring)
        n := r.nodeMap[r.ring[pos]]
        if !seen[n] {
            seen[n] = true
            expected = append(expected, n)
        }
    }
    r.mu.RUnlock()

    got := r.LookupN(key, 3)
    if len(got) != len(expected) {
        t.Fatal("LookupN length mismatch")
    }
    for i := range expected {
        if got[i] != expected[i] {
            t.Fatal("LookupN order mismatch")
        }
    }
}

