func TestRing_Lookup_ExactMatch_SmallestAndLargest(t *testing.T) {
	r := NewRing(32)
	r.Add("n1")
	r.Add("n2")
	r.Add("n3")

	r.mu.RLock()
	if len(r.ring) < 2 {
		r.mu.RUnlock()
		t.Fatalf("unexpected small ring: 0", len(r.ring))
	}
	smallest := r.ring[0]
	largest := r.ring[len(r.ring)-1]
	nSmall := r.nodeMap[smallest]
	nLarge := r.nodeMap[largest]
	rep := r.replicas
	r.mu.RUnlock()

	// find indices for those virtual nodes
	iSmall := -1
	for i := 0; i < rep; i++ {
		if virtualNodeHash(nSmall, i) == smallest {
			iSmall = i
			break
		}
	}
	if iSmall < 0 { t.Fatal("cannot locate smallest index") }

	iLarge := -1
	for i := 0; i < rep; i++ {
		if virtualNodeHash(nLarge, i) == largest {
			iLarge = i
			break
		}
	}
	if iLarge < 0 { t.Fatal("cannot locate largest index") }

	kSmall := nSmall + "#" + itoa(iSmall)
	kLarge := nLarge + "#" + itoa(iLarge)
	if got := r.Lookup(kSmall); got != nSmall { t.Fatalf("exact match at smallest: expected " + nSmall + ", got " + got) }
	if got := r.Lookup(kLarge); got != nLarge { t.Fatalf("exact match at largest: expected " + nLarge + ", got " + got) }
}


func itoa(n int) string {
	if n == 0 { return "0" }
	var b [20]byte
	i := len(b)
	for n > 0 {
		rem := n - (n/10)*10
		i--
		b[i] = byte('0' + byte(rem))
		n = n / 10
	}
	return string(b[i:])
}


